import sys

class Solution:
    def checkOdd(self, N: int) -> str:
        return "ODD" if N & 1 else "EVEN"

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        N = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.checkOdd(N)
    print(ans)

solutions.cpp:
#include <numeric>

#include <iostream>
#include <string>

class Solution {
public:
    std::string checkOdd(int N) {
        return (N & 1) ? "ODD" : "EVEN";
    }
};

int main() {
    int N;
    std::cin >> N;
    Solution sol;
    std::cout << sol.checkOdd(N) << std::endl;
    return 0;
}
